import React, { useId } from 'react';
import { Card, CardContent, Box, Typography, Stack, LinearProgress } from '@mui/material';
import { ResponsiveChartContainer, BarPlot, ChartsXAxis, ChartsYAxis, ChartsClipPath } from '@mui/x-charts';
import response from './response.json';

interface GoalProgress {
  day: string;
  amount: number;
}

interface CampaignData {
  campaign: {
    title: string;
    totalRaised: number;
    goal: number;
    donorCount: number;
  };
  goalProgress: GoalProgress[];
  progressPercent: number;
}

export default function Widget() {
  const data = response.data as CampaignData;
  const clipPathId = useId();

  return (
    <Card sx={{ width: 'fit-content', minWidth: 350, maxWidth: 500, bgcolor: '#303030' }} elevation={3}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" sx={{ color: '#FFC107', mb: 1 }}>
              {data.campaign.title}
            </Typography>
            <Typography variant="body2" sx={{ color: '#FF5722' }}>
              ${data.campaign.totalRaised.toLocaleString()} raised of ${data.campaign.goal.toLocaleString()} goal
            </Typography>
            <Typography variant="body2" sx={{ color: '#FFC107', mt: 0.5 }}>
              {data.campaign.donorCount} donors
            </Typography>
          </Box>

          <Box>
            <Stack direction="row" justifyContent="space-between" sx={{ mb: 0.5 }}>
              <Typography variant="caption" color="text.secondary">
                Progress
              </Typography>
              <Typography variant="caption" fontWeight={600} sx={{ color: '#FF5722' }}>
                {data.progressPercent}%
              </Typography>
            </Stack>
            <LinearProgress
              variant="determinate"
              value={data.progressPercent}
              sx={{
                height: 8,
                borderRadius: 4,
                bgcolor: '#424242',
                '& .MuiLinearProgress-bar': {
                  bgcolor: '#FF5722',
                  borderRadius: 4,
                },
              }}
            />
          </Box>

          <Box sx={{ width: '100%', height: 200 }}>
            <ResponsiveChartContainer
              series={[
                {
                  type: 'bar',
                  data: data.goalProgress.map(gp => gp.amount),
                  color: '#FFC107',
                },
              ]}
              xAxis={[
                {
                  scaleType: 'band',
                  data: data.goalProgress.map(gp => gp.day),
                  id: 'days',
                },
              ]}
              yAxis={[{ id: 'amount' }]}
            >
              <g clipPath={`url(#${clipPathId})`}>
                <BarPlot />
              </g>
              <ChartsXAxis
                axisId="days"
                tickLabelStyle={{ fontSize: 10, fill: '#BDBDBD' }}
              />
              <ChartsYAxis
                axisId="amount"
                tickLabelStyle={{ fontSize: 10, fill: '#BDBDBD' }}
              />
              <ChartsClipPath id={clipPathId} />
            </ResponsiveChartContainer>
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
